draw(3*dir(240)--3*dir(60),red);
draw((-2,0)--(2,0));
draw((0,-3)--(0,3));

label("$\frac{\pi}{3}$", (0.5,0.4));
label("$\theta = \frac{\pi}{3}$", (2,1.8), red);
